import { useNavigate } from "react-router-dom";
import Logo from "../assets/favicon.svg";

const NotFound = () => {
  const navigate = useNavigate();
  return (
    <div
      className="w-full h-screen flex justify-center items-center px-4 sm:px-6 md:px-12 cursor-pointer"
      onClick={() => navigate("/")}
    >
      <div className="relative w-full max-w-5xl bg-lime-500 shadow-[0_0_60px_0px_rgba(26,46,5,0.5)] overflow-hidden rounded-2xl h-[280px] sm:h-[320px] md:h-[360px] flex transition-all duration-300 ease-in-out">
        {/* 404 Number */}
        <h1 className="text-white/10 text-[180px] sm:text-[260px] md:text-[360px] lg:text-[400px] absolute top-1/2 left-4 -translate-y-1/2 font-sans font-extrabold select-none pointer-events-none">
          404
        </h1>

        {/* Main Content */}
        <div className="absolute pl-[45%] w-full h-full bg-black/20 rounded-2xl flex flex-col justify-center sm:items-start items-center text-center sm:text-left">
          <div className="absolute -top-28 left-0 w-[250px] h-[250px] sm:w-[300px] sm:h-[300px] rounded-full bg-gradient-to-b from-black via-black to-black/30" />
          <div className="absolute left-4 sm:left-12 top-4 w-[120px] sm:w-[160px] md:w-[200px] z-10">
            <img
              src={Logo}
              alt="Startup Logo"
              className="w-full h-auto drop-shadow-xl"
            />
          </div>
          <p className="text-4xl sm:text-5xl md:text-6xl font-extrabold text-white mt-10 sm:mt-0">
            Oops!
          </p>
          <p className="text-base sm:text-lg md:text-xl text-white/60 mt-3">
            Sorry, the page you visited does not exist.
          </p>
        </div>

        {/* Bottom Right Note */}
        <div className="absolute bottom-6 right-6 sm:right-12 text-sm sm:text-base md:text-lg text-white/60 font-semibold z-20">
          Page Not Found!
          <div className="absolute w-[120px] h-[120px] sm:w-[200px] sm:h-[200px] rounded-full bg-gradient-to-t from-black via-black to-black/30 -z-10 bottom-0 right-0 translate-x-1/2 translate-y-1/2" />
        </div>
      </div>
    </div>
  );
};

export default NotFound;
